commands_executed:
awk 'BEGIN{OFS=FS}
{ if ($1 ~ /^#/) {print; next}
  if ($2=="/boot") {
    if ($4 !~ /(^|,)(nosuid)(,|$)/) {
      $4=$4==""?"nosuid":$4",nosuid"
    }
    if ($6 !~ /^[0-9]+$/) {
      $6="0"
    }
  }
  print
}' /etc/fstab > /tmp/fstab_new

